const nodemailer = require('nodemailer');
const fs = require('fs');

async function sendEmail() {
  try {
    // Read the report generated by Playwright
    let reportData = {};
    if (fs.existsSync('data/report.json')) {
      reportData = JSON.parse(fs.readFileSync('data/report.json', 'utf8'));
    }

    // Create transporter
    const transporter = nodemailer.createTransport({
      host: process.env.SMTP_HOST,
      port: parseInt(process.env.SMTP_PORT),
      secure: process.env.SMTP_PORT === '465',
      auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASSWORD,
      },
    });

    // Build email with Playwright data
    const mailOptions = {
      from: process.env.EMAIL_FROM,
      to: process.env.EMAIL_TO,
      subject: `Automated Report - ${new Date().toDateString()}`,
      html: `
        <h2>Weekly Automated Report</h2>
        <p>Generated by Playwright on GitHub Actions</p>
        <hr/>
        <h3>Report Details</h3>
        <p><strong>Timestamp:</strong> ${reportData.timestamp || 'N/A'}</p>
        <p><strong>Title:</strong> ${reportData.title || 'N/A'}</p>
        <p><strong>Content:</strong> ${reportData.content || 'N/A'}</p>
        <p><strong>Status:</strong> ${reportData.status || 'Unknown'}</p>
        <hr/>
        <p><em>This email was automatically generated.</em></p>
      `,
    };

    // Send email
    const info = await transporter.sendMail(mailOptions);
    console.log('Email sent successfully:', info.response);
    process.exit(0);
    
  } catch (error) {
    console.error('Error sending email:', error);
    process.exit(1);
  }
}

sendEmail();